//! Death #6: Death of Destructive Interference (Perfect Phase Lock).
//!
//! Runtime counterpart to `Gnosis/SixthDeathInterference.lean`.
//!
//! Lean specifies: at perfect-density `R`, every interference event between
//! two `BuleyUnit` states whose score equals `R` is purely constructive.
//! Destructive interference (the noise/dissonance term) collapses to zero.
//!
//! The perfect-density set is `R ∈ {17, 34, 51}` (Triton/Hexon/Enneon),
//! i.e. `R = 17·k` for `k ∈ {1, 2, 3}` — these are NOT magic numbers but
//! the densities at which the manifold pins to its harmonic basis.
//!
//! Lean theorem (paraphrased):
//! ```text
//! theorem death_of_interference (R : Nat) (hPerfect : R = 17 ∨ R = 34 ∨ R = 51) :
//!     ∃ (M : BuleyUnit), buleyUnitScore M = R ∧
//!       buleyUnitScore (destructive_interference M M) = 0
//! ```
//! The Lean witness is `⟨R, 0, 0⟩`; we mirror that here.

/// A BuleyUnit on the runtime side.
///
/// Mirrors the Lean structure `BuleyUnit { rim, void, rigidity }` from
/// `Gnosis.SpectralNoiseEquilibrium`. Field names are lowercase to match Lean.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct BuleyUnit {
    pub rim: u32,
    pub void: u32,
    pub rigidity: u32,
}

impl BuleyUnit {
    /// `buleyUnitScore`: pointwise sum of the three fields.
    pub fn score(&self) -> u32 {
        self.rim
            .saturating_add(self.void)
            .saturating_add(self.rigidity)
    }
}

/// Constructive interference: pointwise add. Score sums.
///
/// Uses `saturating_add` to mirror Nat semantics (no overflow trap) — at the
/// perfect densities of interest (R ≤ 51), the sum is well below `u32::MAX`.
pub fn constructive_interference(a: &BuleyUnit, b: &BuleyUnit) -> BuleyUnit {
    BuleyUnit {
        rim: a.rim.saturating_add(b.rim),
        void: a.void.saturating_add(b.void),
        rigidity: a.rigidity.saturating_add(b.rigidity),
    }
}

/// Destructive interference: pointwise saturating subtract.
///
/// At `a == b` this yields `⟨0, 0, 0⟩` — the death-of-interference witness.
/// Saturating subtract guarantees no underflow when `b.field > a.field`.
pub fn destructive_interference(a: &BuleyUnit, b: &BuleyUnit) -> BuleyUnit {
    BuleyUnit {
        rim: a.rim.saturating_sub(b.rim),
        void: a.void.saturating_sub(b.void),
        rigidity: a.rigidity.saturating_sub(b.rigidity),
    }
}

/// Perfect Phase Lock at density `R`.
///
/// Returns true iff `R ∈ {17, 34, 51}` (the Triton/Hexon/Enneon densities
/// from `Gnosis.SixthDeathInterference.death_of_interference`).
#[allow(non_snake_case)]
pub fn is_perfect_phase_lock(R: u32) -> bool {
    matches!(R, 17 | 34 | 51)
}

/// Witness from the Lean theorem `death_of_interference`.
///
/// At perfect-density `R`, returns `Some(M)` where `M = ⟨R, 0, 0⟩` satisfies:
///   * `M.score() == R`
///   * `destructive_interference(M, M).score() == 0`
///
/// Returns `None` for any `R` outside the perfect-density set.
#[allow(non_snake_case)]
pub fn perfect_phase_lock_witness(R: u32) -> Option<BuleyUnit> {
    if is_perfect_phase_lock(R) {
        // Mirror Lean: refine ⟨⟨R, 0, 0⟩, rfl, ?_⟩
        Some(BuleyUnit {
            rim: R,
            void: 0,
            rigidity: 0,
        })
    } else {
        None
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn score_is_field_sum() {
        let u = BuleyUnit {
            rim: 5,
            void: 7,
            rigidity: 11,
        };
        assert_eq!(u.score(), 23);

        let zero = BuleyUnit {
            rim: 0,
            void: 0,
            rigidity: 0,
        };
        assert_eq!(zero.score(), 0);

        // Lean witness at R=17: ⟨17, 0, 0⟩ scores to 17.
        let witness = BuleyUnit {
            rim: 17,
            void: 0,
            rigidity: 0,
        };
        assert_eq!(witness.score(), 17);
    }

    #[test]
    fn constructive_at_perfect_density_doubles_score() {
        for &r in &[17u32, 34, 51] {
            // Two units at score=R with different field distributions.
            let a = BuleyUnit {
                rim: r,
                void: 0,
                rigidity: 0,
            };
            let b = BuleyUnit {
                rim: 0,
                void: r,
                rigidity: 0,
            };
            assert_eq!(a.score(), r);
            assert_eq!(b.score(), r);
            let composed = constructive_interference(&a, &b);
            assert_eq!(
                composed.score(),
                2 * r,
                "constructive at R={} should sum to 2R={}",
                r,
                2 * r
            );
        }
    }

    #[test]
    fn destructive_at_perfect_density_is_zero() {
        for &r in &[17u32, 34, 51] {
            let m = perfect_phase_lock_witness(r).expect("witness exists at perfect R");
            let dissonance = destructive_interference(&m, &m);
            assert_eq!(
                dissonance.score(),
                0,
                "destructive(M,M) at R={} must vanish",
                r
            );
        }
    }

    #[test]
    fn is_perfect_phase_lock_matches_lean() {
        // True for the three Triton/Hexon/Enneon densities.
        assert!(is_perfect_phase_lock(17));
        assert!(is_perfect_phase_lock(34));
        assert!(is_perfect_phase_lock(51));

        // False everywhere else — sample boundary points and a far value.
        for &r in &[0u32, 1, 16, 18, 33, 35, 50, 52, 100] {
            assert!(
                !is_perfect_phase_lock(r),
                "R={} must NOT be a perfect-phase-lock density",
                r
            );
        }
    }

    #[test]
    #[allow(non_snake_case)]
    fn witness_exists_at_each_perfect_R() {
        for &r in &[17u32, 34, 51] {
            let w = perfect_phase_lock_witness(r);
            assert!(w.is_some(), "expected Some(witness) at R={}", r);
            let m = w.unwrap();
            assert_eq!(m.score(), r, "witness score must equal R={}", r);
        }

        for &r in &[0u32, 1, 16, 18, 33, 35, 50, 52, 100] {
            assert!(
                perfect_phase_lock_witness(r).is_none(),
                "expected None at R={} (not a perfect density)",
                r
            );
        }
    }

    #[test]
    fn destructive_self_zero_concrete() {
        // The Lean death_of_interference witness, instantiated at R=17.
        let m = perfect_phase_lock_witness(17).expect("R=17 is perfect");
        assert_eq!(m.score(), 17);
        let collision = destructive_interference(&m, &m);
        assert_eq!(
            collision.score(),
            0,
            "destructive(M,M) at R=17 must equal 0 (death of interference)"
        );
        // And it's the all-zeros unit, structurally.
        assert_eq!(
            collision,
            BuleyUnit {
                rim: 0,
                void: 0,
                rigidity: 0
            }
        );
    }
}
